struct Node {
    int data;
    Node* next;
};
Node* newNode(int data) {
    Node* node = new Node();
    node->data = data;
    node->next = nullptr;
    return node;
}
Node* reverse_in_groups(Node* head, int k) {
    Node* current = head;
    Node* prev = nullptr;
    Node* next_node = nullptr;
    int count = 0;
    while (current && count < k) {
        next_node = current->next;
        current->next = prev;
        prev = current;
        current = next_node;
        count += 1;
    }
    if (next_node) {
        head->next = reverse_in_groups(next_node, k);
    }
    return prev;
}
void print_list(Node* head) {
    while (head) {
        cout << head->data << ' ';
        head = head->next;
    }
    cout << endl;
}
int main() {
    int n, k;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    cin >> k;
    Node* head = nullptr;
    for (int num : nums) {
        Node* node = newNode(num);
        if (!head) {
            head = node;
        } else {
            Node* current = head;
            while (current->next) {
                current = current->next;
            }
            current->next = node;
